@namespace sv_a2b95717e1af4aca8b173900945277ff.Components.Pages.Settings
@using sv_a2b95717e1af4aca8b173900945277ff.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Profile</h2>

    @if (_loading)
    {
        <p>Loading profile...</p>
    }
    else
    {
        <div class="avatar-preview">
            <img src="@_avatarUrl" alt="Avatar" class="avatar-image" />
            <p class="avatar-url">@_avatarUrl</p>
        </div>

        <div class="form-group">
            <label for="displayName">Display Name</label>
            <input id="displayName" type="text" @bind="_displayName" />
        </div>

        <div class="form-group">
            <label for="email">Email</label>
            <input id="email" type="email" @bind="_email" />
        </div>

        <div class="form-group">
            <label for="bio">Bio</label>
            <textarea id="bio" @bind="_bio" rows="4"></textarea>
        </div>

        <div class="button-group">
            <button class="btn-primary" @onclick="SaveAsync">Save Changes</button>
            <button class="btn-secondary" @onclick="Discard">Discard Changes</button>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="toast-message @_messageClass">@_message</div>
        }
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _loading = true;
    private string _message = "";
    private string _messageClass = "";

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _message = "Profile saved successfully!";
        _messageClass = "toast-success";
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _message = "Changes discarded.";
        _messageClass = "toast-info";
    }
}

@namespace sv_a2b95717e1af4aca8b173900945277ff.Components.Pages.Settings
@using sv_a2b95717e1af4aca8b173900945277ff.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Notifications</h2>

    @if (_loading)
    {
        <p>Loading notification preferences...</p>
    }
    else
    {
        <div class="toggle-group">
            <label class="toggle-item">
                <input type="checkbox" @bind="_emailNotifications" />
                <span>Email Notifications</span>
            </label>
            <label class="toggle-item">
                <input type="checkbox" @bind="_pushNotifications" />
                <span>Push Notifications</span>
            </label>
            <label class="toggle-item">
                <input type="checkbox" @bind="_weeklyDigest" />
                <span>Weekly Digest</span>
            </label>
        </div>

        <h3>Muted Channels</h3>
        <div class="channel-list">
            @foreach (var channel in _channels)
            {
                <label class="toggle-item">
                    <input type="checkbox"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                    <span>@channel</span>
                </label>
            }
        </div>

        <div class="button-group">
            <button class="btn-primary" @onclick="SaveAsync">Save Preferences</button>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="toast-message toast-success">@_message</div>
        }
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private List<string> _channels = new() { "general", "announcements", "random", "support", "engineering" };
    private bool _loading = true;
    private string _message = "";

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _message = "Preferences saved!";
    }
}

@namespace sv_a2b95717e1af4aca8b173900945277ff.Components.Pages.Settings
@using sv_a2b95717e1af4aca8b173900945277ff.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Security</h2>

    @if (_loading)
    {
        <p>Loading security settings...</p>
    }
    else
    {
        <!-- Change Password Panel -->
        <div class="expandable-panel">
            <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>Change Password</span>
                <span class="expand-icon">@(_passwordPanelOpen ? "▼" : "▶")</span>
            </button>
            @if (_passwordPanelOpen)
            {
                <div class="panel-content">
                    <div class="form-group">
                        <label for="currentPassword">Current Password</label>
                        <input id="currentPassword" type="password" @bind="_currentPassword" />
                    </div>
                    <div class="form-group">
                        <label for="newPassword">New Password</label>
                        <input id="newPassword" type="password" @bind="_newPassword" />
                    </div>
                    <div class="form-group">
                        <label for="confirmPassword">Confirm Password</label>
                        <input id="confirmPassword" type="password" @bind="_confirmPassword" />
                    </div>
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="toast-message toast-error">@_passwordError</div>
                    }
                    @if (!string.IsNullOrEmpty(_passwordSuccess))
                    {
                        <div class="toast-message toast-success">@_passwordSuccess</div>
                    }
                    <button class="btn-primary" @onclick="ChangePasswordAsync">Update Password</button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="tfa-section">
            <h3>Two-Factor Authentication</h3>
            <div class="tfa-status">
                <span class="status-indicator @(_twoFactorEnabled ? "status-on" : "status-off")"></span>
                <span>@(_twoFactorEnabled ? "Enabled" : "Disabled")</span>
                <label class="toggle-item">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span>Toggle 2FA</span>
                </label>
            </div>
            @if (_lastPasswordChange.HasValue)
            {
                <p class="info-text">Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }
        </div>

        <!-- Active Sessions -->
        <div class="sessions-section">
            <h3>Active Sessions</h3>
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th>Action</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (session != _sessions.FirstOrDefault())
                                {
                                    <button class="btn-danger btn-small" @onclick="() => ConfirmRevoke(session)">Revoke</button>
                                }
                                else
                                {
                                    <span class="current-badge">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="dialog-overlay">
                <div class="dialog">
                    <h4>Revoke Session</h4>
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                    <div class="button-group">
                        <button class="btn-danger" @onclick="RevokeSessionAsync">Confirm Revoke</button>
                        <button class="btn-secondary" @onclick="() => _sessionToRevoke = null">Cancel</button>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string _passwordError = "";
    private string _passwordSuccess = "";
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = "";
        _passwordSuccess = "";

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "New password cannot be empty.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _passwordSuccess = "Password updated successfully!";
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }

    private void ConfirmRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task RevokeSessionAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.Remove(_sessionToRevoke);
            _sessionToRevoke = null;
        }
    }
}

