namespace sv_a2b95717e1af4aca8b173900945277ff.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_a2b95717e1af4aca8b173900945277ff.Components.Pages.Settings

<nav class="settings-sidebar">
    <ul>
        @foreach (var section in Sections)
        {
            <li class="@(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionSelected.InvokeAsync(section)">
                <span class="sidebar-icon">@GetIcon(section)</span>
                <span class="sidebar-label">@section</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = { "Profile", "Notifications", "Security", "Appearance" };

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_a2b95717e1af4aca8b173900945277ff.Components.Pages.Settings
@using sv_a2b95717e1af4aca8b173900945277ff.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Profile</h2>

    @if (_loading)
    {
        <p>Loading profile...</p>
    }
    else
    {
        <div class="avatar-preview">
            <img src="@_avatarUrl" alt="Avatar" class="avatar-image" />
            <p class="avatar-url">@_avatarUrl</p>
        </div>

        <div class="form-group">
            <label for="displayName">Display Name</label>
            <input id="displayName" type="text" @bind="_displayName" />
        </div>

        <div class="form-group">
            <label for="email">Email</label>
            <input id="email" type="email" @bind="_email" />
        </div>

        <div class="form-group">
            <label for="bio">Bio</label>
            <textarea id="bio" @bind="_bio" rows="4"></textarea>
        </div>

        <div class="button-group">
            <button class="btn-primary" @onclick="SaveAsync">Save Changes</button>
            <button class="btn-secondary" @onclick="Discard">Discard Changes</button>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="toast-message @_messageClass">@_message</div>
        }
    }
</div>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _loading = true;
    private string _message = "";
    private string _messageClass = "";

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _message = "Profile saved successfully!";
        _messageClass = "toast-success";
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _message = "Changes discarded.";
        _messageClass = "toast-info";
    }
}

