@namespace sv_a2b95717e1af4aca8b173900945277ff.Components.Pages.Settings
@using sv_a2b95717e1af4aca8b173900945277ff.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Appearance</h2>

    @if (_loading)
    {
        <p>Loading appearance settings...</p>
    }
    else
    {
        <!-- Theme Selector -->
        <div class="form-group">
            <label>Theme</label>
            <div class="radio-group">
                <label class="radio-item">
                    <input type="radio" name="theme" value="Light" @onchange="() => _theme = &quot;Light&quot;" checked="@(_theme == "Light")" />
                    <span>Light</span>
                </label>
                <label class="radio-item">
                    <input type="radio" name="theme" value="Dark" @onchange="() => _theme = &quot;Dark&quot;" checked="@(_theme == "Dark")" />
                    <span>Dark</span>
                </label>
                <label class="radio-item">
                    <input type="radio" name="theme" value="System" @onchange="() => _theme = &quot;System&quot;" checked="@(_theme == "System")" />
                    <span>System</span>
                </label>
            </div>
        </div>

        <!-- Font Size Selector -->
        <div class="form-group">
            <label>Font Size</label>
            <div class="radio-group">
                <label class="radio-item">
                    <input type="radio" name="fontSize" value="Small" @onchange="() => _fontSize = &quot;Small&quot;" checked="@(_fontSize == "Small")" />
                    <span>Small</span>
                </label>
                <label class="radio-item">
                    <input type="radio" name="fontSize" value="Medium" @onchange="() => _fontSize = &quot;Medium&quot;" checked="@(_fontSize == "Medium")" />
                    <span>Medium</span>
                </label>
                <label class="radio-item">
                    <input type="radio" name="fontSize" value="Large" @onchange="() => _fontSize = &quot;Large&quot;" checked="@(_fontSize == "Large")" />
                    <span>Large</span>
                </label>
            </div>
        </div>

        <!-- Language Dropdown -->
        <div class="form-group">
            <label for="language">Language</label>
            <select id="language" @bind="_language">
                <option value="en">English</option>
                <option value="es">Spanish</option>
                <option value="fr">French</option>
                <option value="de">German</option>
                <option value="ja">Japanese</option>
                <option value="zh">Chinese</option>
            </select>
        </div>

        <!-- Compact Mode -->
        <div class="form-group">
            <label class="toggle-item">
                <input type="checkbox" @bind="_compactMode" />
                <span>Compact Mode</span>
            </label>
        </div>

        <!-- Live Preview -->
        <div class="preview-area @GetPreviewClasses()">
            <h4>Preview</h4>
            <p>This is how your content will look with the selected settings.</p>
            <p>The quick brown fox jumps over the lazy dog.</p>
        </div>

        <div class="button-group">
            <button class="btn-primary" @onclick="SaveAsync">Save</button>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="toast-message toast-success">@_message</div>
        }
    }
</div>

@code {
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _loading = true;
    private string _message = "";

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var classes = $"preview-theme-{_theme.ToLowerInvariant()} preview-font-{_fontSize.ToLowerInvariant()}";
        if (_compactMode)
            classes += " preview-compact";
        return classes;
    }

    private async Task SaveAsync()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance settings saved!";
    }
}

@page "/settings"
@namespace sv_a2b95717e1af4aca8b173900945277ff.Components.Pages.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionSelected="SetActiveSection" />

    <main class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </main>
</div>

@code {
    private string _activeSection = "Profile";

    private void SetActiveSection(string section)
    {
        _activeSection = section;
    }
}

.settings-dashboard {
    display: flex;
    min-height: 100vh;
    gap: 0;
}

::deep .settings-sidebar {
    width: 240px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
}

::deep .settings-sidebar ul {
    list-style: none;
    padding: 0;
    margin: 0;
}

::deep .settings-sidebar li {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.5rem;
    cursor: pointer;
    transition: background-color 0.2s, border-left 0.2s;
    border-left: 3px solid transparent;
}

::deep .settings-sidebar li:hover {
    background: #e9ecef;
}

::deep .settings-sidebar li.active {
    background: #e7f1ff;
    border-left-color: #0d6efd;
    font-weight: 600;
    color: #0d6efd;
}

::deep .sidebar-icon {
    font-size: 1.2rem;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 800px;
}

::deep .settings-section h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    font-size: 1.5rem;
    color: #212529;
}

::deep .form-group {
    margin-bottom: 1rem;
}

::deep .form-group label {
    display: block;
    margin-bottom: 0.25rem;
    font-weight: 500;
    color: #495057;
}

::deep .form-group input[type="text"],
::deep .form-group input[type="email"],
::deep .form-group input[type="password"],
::deep .form-group textarea,
::deep .form-group select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 4px;
    font-size: 1rem;
}

::deep .form-group textarea {
    resize: vertical;
}

::deep .button-group {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

::deep .btn-primary {
    background: #0d6efd;
    color: white;
    border: none;
    padding: 0.5rem 1.25rem;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

::deep .btn-primary:hover {
    background: #0b5ed7;
}

::deep .btn-secondary {
    background: #6c757d;
    color: white;
    border: none;
    padding: 0.5rem 1.25rem;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

::deep .btn-secondary:hover {
    background: #5c636a;
}

::deep .btn-danger {
    background: #dc3545;
    color: white;
    border: none;
    padding: 0.5rem 1.25rem;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

::deep .btn-danger:hover {
    background: #bb2d3b;
}

::deep .btn-small {
    padding: 0.25rem 0.75rem;
    font-size: 0.8rem;
}

::deep .toast-message {
    margin-top: 1rem;
    padding: 0.75rem 1rem;
    border-radius: 4px;
    font-size: 0.9rem;
}

::deep .toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

::deep .toast-info {
    background: #cff4fc;
    color: #055160;
    border: 1px solid #b6effb;
}

::deep .toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

/* Avatar */
::deep .avatar-preview {
    margin-bottom: 1.5rem;
    text-align: center;
}

::deep .avatar-image {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

::deep .avatar-url {
    font-size: 0.8rem;
    color: #6c757d;
    margin-top: 0.5rem;
    word-break: break-all;
}

/* Toggles */
::deep .toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
    margin-bottom: 1.5rem;
}

::deep .toggle-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
}

::deep .toggle-item input[type="checkbox"] {
    width: 1.1rem;
    height: 1.1rem;
}

/* Channel list */
::deep .channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-bottom: 1rem;
    padding-left: 0.5rem;
}

/* Security - Expandable Panel */
::deep .expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 1.5rem;
}

::deep .panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 500;
}

::deep .panel-header:hover {
    background: #e9ecef;
}

::deep .panel-content {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

/* 2FA */
::deep .tfa-section {
    margin-bottom: 1.5rem;
}

::deep .tfa-status {
    display: flex;
    align-items: center;
    gap: 0.75rem;
}

::deep .status-indicator {
    width: 12px;
    height: 12px;
    border-radius: 50%;
}

::deep .status-on {
    background: #198754;
}

::deep .status-off {
    background: #dc3545;
}

::deep .info-text {
    font-size: 0.85rem;
    color: #6c757d;
    margin-top: 0.5rem;
}

/* Sessions table */
::deep .sessions-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 0.75rem;
}

::deep .sessions-table th,
::deep .sessions-table td {
    padding: 0.6rem 0.75rem;
    text-align: left;
    border-bottom: 1px solid #dee2e6;
}

::deep .sessions-table th {
    background: #f8f9fa;
    font-weight: 600;
    font-size: 0.85rem;
    text-transform: uppercase;
    color: #6c757d;
}

::deep .current-badge {
    background: #e7f1ff;
    color: #0d6efd;
    padding: 0.2rem 0.5rem;
    border-radius: 3px;
    font-size: 0.8rem;
    font-weight: 500;
}

/* Dialog */
::deep .dialog-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

::deep .dialog {
    background: white;
    border-radius: 8px;
    padding: 1.5rem;
    max-width: 400px;
    width: 90%;
    box-shadow: 0 4px 24px rgba(0, 0, 0, 0.2);
}

::deep .dialog h4 {
    margin-top: 0;
}

/* Radio groups */
::deep .radio-group {
    display: flex;
    gap: 1.5rem;
    margin-top: 0.25rem;
}

::deep .radio-item {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
}

/* Appearance preview */
::deep .preview-area {
    margin-top: 1.5rem;
    padding: 1.5rem;
    border: 2px dashed #dee2e6;
    border-radius: 8px;
    transition: all 0.3s;
}

::deep .preview-theme-light {
    background: #ffffff;
    color: #212529;
}

::deep .preview-theme-dark {
    background: #212529;
    color: #f8f9fa;
}

::deep .preview-theme-system {
    background: #f0f0f0;
    color: #333;
}

::deep .preview-font-small {
    font-size: 0.85rem;
}

::deep .preview-font-medium {
    font-size: 1rem;
}

::deep .preview-font-large {
    font-size: 1.2rem;
}

::deep .preview-compact {
    padding: 0.75rem;
    line-height: 1.3;
}

